#!/usr/bin/perl
use strict;
use warnings;
use PDF::API2;
use Text::Unidecode;

# Function to extract information from a PDF file
sub extract_info {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2->open($pdf_file);

    my $info = {};

    # Extract metadata
    $info->{date} = $pdf->info->get('ModDate');
    $info->{author} = $pdf->info->get('Author');

    # Extract table information
    my $page = $pdf->page(1);  # Assuming the table is on the first page
    my $text = $page->text;

    # Convert Unicode to ASCII for easier processing
    $text = unidecode $text;

    # Define a pattern to match a simple table
    my $table_pattern = qr/\d+(\s+\d+)+/g;

    # Find all matches of the table pattern
    if ($text =~ /$table_pattern/g) {
        $info->{table} = [ map { [ split /\s+/ ] } $text =~ /$table_pattern/g ];
    } else {
        $info->{table} = [];
    }

    return $info;
}

# Usage
my $pdf_file = 'example.pdf';
my $info = extract_info($pdf_file);

# Print the extracted information
print "Date: $info->{date}\n";
print "Author: $info->{author}\n";
print "Table:\n";
foreach my $row (@{$info->{table}}) {
    print join("\t", @$row), "\n";
}

